-- Badge Rules Migration
-- Extracted from /api/fun-facts endpoint in main.py
-- Migrates all hardcoded SQL badge queries into the badge_rules table
--
-- New schema:
--   id INTEGER PRIMARY KEY AUTOINCREMENT
--   badge_name TEXT NOT NULL UNIQUE
--   sql_query TEXT NOT NULL
--   result_type TEXT DEFAULT 'top'   -- 'top' = return top 1 row, 'count' = return count, 'boolean' = yes/no check
--   description TEXT
--   active INTEGER DEFAULT 1
--
-- result_type classification:
--   'top'      = queries with LIMIT 1 that return a ranked person
--   'count'    = queries returning aggregate counts (not yet used, but reserved)
--   'boolean'  = queries with HAVING/SUM/CASE checks that return a conditional result
--
-- Note: Queries that reference Python variables (cutoff_90, cutoff_30, cutoff_60, cutoff_7, today)
--       have been converted to use SQLite date functions or parameter placeholders {PARAM_N}.
--       The application layer should substitute these parameters before execution.
--       Placeholder mapping:
--         {PARAM_1} = cutoff_90 (summary_days, default 90 days)
--         {PARAM_2} = cutoff_30 (activity_days, default 30 days)
--         {PARAM_3} = cutoff_60 (long_streak_days, default 60 days)
--         {PARAM_4} = cutoff_7 (streak_days, default 7 days)
--         {PARAM_5} = today (current date)

-- ============================================================================
-- SECTION 1: Status-based badges (blocked, vague, in_progress, done, leave)
-- ============================================================================

INSERT OR IGNORE INTO badge_rules (badge_name, sql_query, result_type, description) VALUES
('Blocker Magnet', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status=''blocked'' GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most blocked updates'),
('Vague Victor', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status=''vague'' GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most vague updates'),
('Leave Taker', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most leave entries'),
('Done Streak', 'SELECT name, COUNT(*) as streak FROM (SELECT name, date, date(date, ''-'' || (ROW_NUMBER() OVER (PARTITION BY name ORDER BY date) - 1) || '' days'') as grp FROM updates WHERE status = ''done'' AND date >= {PARAM_2}) GROUP BY name, grp ORDER BY streak DESC LIMIT 1', 'top', 'Longest consecutive done days'),
('Blocker to Done', 'SELECT name, COUNT(*) as cnt FROM (SELECT a.name, a.module, a.date as blocked_date, b.date as done_date FROM updates a JOIN updates b ON a.name = b.name AND a.module = b.module WHERE a.status = ''blocked'' AND b.status = ''done'' AND b.date >= a.date AND b.date >= {PARAM_1}) GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most blocked tasks resolved to done'),
('Unblocker', 'SELECT name, COUNT(*) as cnt FROM updates a WHERE a.status = ''done'' AND EXISTS (SELECT 1 FROM updates b WHERE b.name = a.name AND b.module = a.module AND b.status = ''blocked'' AND b.date < a.date AND julianday(a.date) - julianday(b.date) <= 7) AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Resolved blocked tasks within a week'),
('Reopener', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''in_progress'' AND module IN (SELECT module FROM updates u2 WHERE u2.name = updates.name AND u2.status = ''done'') AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most reopened tasks'),
('Status Flipper', 'SELECT name, COUNT(*) as cnt FROM (SELECT name, module, date, status, LAG(status) OVER (PARTITION BY name, module ORDER BY date) as prev_status FROM updates WHERE date >= {PARAM_1}) WHERE status != prev_status AND prev_status IS NOT NULL GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most status changes'),
('Status Chameleon', 'SELECT name, COUNT(DISTINCT status) as cnt FROM updates WHERE date >= {PARAM_2} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Uses the most distinct statuses'),
('Always In Progress', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''in_progress'' AND date >= {PARAM_2} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most in_progress updates'),
('Always Done', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''done'' AND date >= {PARAM_2} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most done updates'),
('Zero Blocked', 'SELECT name, COUNT(*) as total FROM updates WHERE date >= {PARAM_1} GROUP BY name HAVING SUM(CASE WHEN status = ''blocked'' THEN 1 ELSE 0 END) = 0 ORDER BY total DESC LIMIT 1', 'top', 'No blockers among active members'),
('First Today', 'SELECT name, MIN(created_at) as ts FROM updates WHERE date = {PARAM_5} GROUP BY name ORDER BY ts LIMIT 1', 'top', 'First person to submit today'),
('Last Today', 'SELECT name, MAX(created_at) as ts FROM updates WHERE date = {PARAM_5} GROUP BY name ORDER BY ts DESC LIMIT 1', 'top', 'Last person to submit today'),
('Daily Logger', 'SELECT name, COUNT(*) as cnt FROM updates WHERE date = {PARAM_5} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most updates today'),
('Update Count Today', 'SELECT name, COUNT(*) as cnt FROM updates WHERE date = {PARAM_5} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most updates submitted today');

