INSERT OR IGNORE INTO badge_rules (badge_name, sql_query, result_type, description) VALUES
('Peak Hour', 'SELECT strftime(''%H'', created_at) as hour, COUNT(*) as cnt FROM updates WHERE date >= {PARAM_1} GROUP BY strftime(''%H'', created_at) ORDER BY cnt DESC LIMIT 1', 'top', 'Peak update hour'),
('Power Day', 'SELECT CASE strftime(''%w'', date) WHEN ''0'' THEN ''Sunday'' WHEN ''1'' THEN ''Monday'' WHEN ''2'' THEN ''Tuesday'' WHEN ''3'' THEN ''Wednesday'' WHEN ''4'' THEN ''Thursday'' WHEN ''5'' THEN ''Friday'' WHEN ''6'' THEN ''Saturday'' END as day, COUNT(*) as cnt FROM updates WHERE status != ''leave'' AND date >= {PARAM_1} GROUP BY strftime(''%w'', date) ORDER BY cnt DESC LIMIT 1', 'top', 'Most active day of week'),
('Early Bird', 'SELECT name, AVG(CAST(strftime(''%H'', created_at) as REAL)) as avg_hour FROM updates WHERE date >= {PARAM_1} GROUP BY name ORDER BY avg_hour ASC LIMIT 1', 'top', 'Earliest average update time'),
('Clockwork', 'SELECT name, AVG((CAST(strftime(''%H'', created_at) as REAL) - 14) * (CAST(strftime(''%H'', created_at) as REAL) - 14)) as variance FROM updates WHERE date >= {PARAM_1} GROUP BY name HAVING COUNT(*) >= 5 ORDER BY variance ASC LIMIT 1', 'top', 'Most consistent update time'),
('Morning Person', 'SELECT name, COUNT(*) as cnt FROM updates WHERE strftime(''%H'', created_at) BETWEEN ''06'' AND ''09'' AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most morning updates between 6-9 AM'),
('Lunch Skipper', 'SELECT name, COUNT(*) as cnt FROM updates WHERE strftime(''%H'', created_at) BETWEEN ''12'' AND ''14'' AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most lunchtime updates'),
('Evening Person', 'SELECT name, COUNT(*) as cnt FROM updates WHERE strftime(''%H'', created_at) BETWEEN ''18'' AND ''23'' AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most evening updates'),
