('Weekend Warrior', 'SELECT name, COUNT(*) as cnt FROM updates WHERE strftime(''%w'', date) IN (''0'', ''6'') AND status != ''leave'' AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most weekend updates'),
