-- ============================================================================
-- SECTION 3: Module and productivity badges
-- ============================================================================

INSERT OR IGNORE INTO badge_rules (badge_name, sql_query, result_type, description) VALUES
('Module Explorer', 'SELECT name, COUNT(DISTINCT module) as cnt FROM updates WHERE module != '''' AND date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 3', 'top', 'Works across most distinct modules'),
('Specialist', 'SELECT name, module, COUNT(*) as cnt, CAST(COUNT(*) as REAL) / (SELECT COUNT(*) FROM updates u2 WHERE u2.name = updates.name AND date >= {PARAM_1}) as pct FROM updates WHERE module != '''' AND date >= {PARAM_1} GROUP BY name, module ORDER BY pct DESC LIMIT 1', 'top', 'Highest module focus percentage'),
('Module Loyalist', 'SELECT name, module, COUNT(*) as cnt FROM updates WHERE module != '''' AND date >= {PARAM_1} GROUP BY name, module ORDER BY cnt DESC LIMIT 1', 'top', 'Most updates in a single module'),
('Module Switcher', 'SELECT name, COUNT(DISTINCT module) as cnt FROM updates WHERE module != '''' AND date >= {PARAM_2} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most modules in 30 days'),
('Single Module Focus', 'SELECT name, COUNT(DISTINCT module) as cnt FROM updates WHERE module != '''' AND date >= {PARAM_2} GROUP BY name ORDER BY cnt ASC LIMIT 1', 'top', 'Least modules - focused on one'),
('Task Juggler', 'SELECT name, AVG(cnt) as avg_tasks FROM (SELECT name, date, COUNT(*) as cnt FROM updates WHERE status != ''leave'' AND date >= {PARAM_2} GROUP BY name, date) GROUP BY name ORDER BY avg_tasks DESC LIMIT 1', 'top', 'Highest average tasks per day'),
('Most Modules Single Day', 'SELECT name, date, COUNT(DISTINCT module) as cnt FROM updates WHERE module != '''' AND date >= {PARAM_1} GROUP BY name, date ORDER BY cnt DESC LIMIT 1', 'top', 'Most modules touched in a single day'),
('Productive Day', 'SELECT name, date, COUNT(*) as cnt FROM updates WHERE status != ''leave'' AND date >= {PARAM_1} GROUP BY name, date ORDER BY cnt DESC LIMIT 1', 'top', 'Most updates in a single day'),
('Momentum Builder', 'SELECT name, COUNT(*) as cnt FROM updates WHERE date >= {PARAM_4} AND status != ''leave'' GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most updates in last 7 days'),
('Quiet Achiever', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''done'' AND date >= {PARAM_2} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most done tasks in 30 days'),
('First Week Done', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''done'' AND date >= {PARAM_4} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most done tasks in last 7 days'),
('Module Maverick', 'SELECT name, COUNT(DISTINCT module) as cnt FROM updates WHERE module != '''' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most modules across 90 days'),
('Focused Specialist', 'SELECT name, module, COUNT(*) as cnt FROM updates WHERE module != '''' AND date >= date(''now'', ''-90 days'') GROUP BY name, module ORDER BY cnt DESC LIMIT 1', 'top', 'Most updates in one module'),
('Rapid Releaser', 'SELECT name, COUNT(*) as cnt FROM updates WHERE description LIKE ''%release%'' OR description LIKE ''%shipped%'' OR description LIKE ''%live%'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most release mentions'),
('Consistency Score', 'SELECT name, (COUNT(DISTINCT date) * 100.0 / (julianday(''now'') - julianday(MIN(date)) + 1)) as score FROM updates WHERE status != ''leave'' AND date >= {PARAM_1} GROUP BY name ORDER BY score DESC LIMIT 1', 'top', 'Highest update consistency percentage'),
('Update Frequency', 'SELECT name, CAST(COUNT(*) as REAL) / COUNT(DISTINCT date) as freq FROM updates WHERE date >= {PARAM_1} GROUP BY name ORDER BY freq DESC LIMIT 1', 'top', 'Highest updates per day ratio'),
('Solo Worker', 'SELECT name, COUNT(DISTINCT date) as days FROM updates WHERE date >= {PARAM_2} GROUP BY name ORDER BY days ASC LIMIT 1', 'top', 'Fewest active days'),
('Team Player', 'SELECT name, COUNT(DISTINCT date) as days FROM updates WHERE date >= {PARAM_2} GROUP BY name ORDER BY days DESC LIMIT 1', 'top', 'Most active days');

-- ============================================================================
-- SECTION 4: Streak and consistency badges
-- ============================================================================

INSERT OR IGNORE INTO badge_rules (badge_name, sql_query, result_type, description) VALUES
('Longest Streak', 'SELECT name, COUNT(*) as streak FROM (SELECT name, date, date(date, ''-'' || (ROW_NUMBER() OVER (PARTITION BY name ORDER BY date) - 1) || '' days'') as grp FROM updates WHERE status != ''leave'' AND date >= {PARAM_3}) GROUP BY name, grp ORDER BY streak DESC LIMIT 1', 'top', 'Longest consecutive work streak'),
('Comeback Kid', 'SELECT name, MAX(julianday(date) - julianday(lag_date)) as gap FROM (SELECT name, date, LAG(date) OVER (PARTITION BY name ORDER BY date) as lag_date FROM updates WHERE status != ''leave'') WHERE lag_date IS NOT NULL ORDER BY gap DESC LIMIT 1', 'top', 'Longest gap between updates'),
('Vacation Mode', 'SELECT name, MAX(julianday(date) - julianday(prev_date)) as gap FROM (SELECT name, date, LAG(date) OVER (PARTITION BY name ORDER BY date) as prev_date FROM updates WHERE status != ''leave'') WHERE prev_date IS NOT NULL ORDER BY gap DESC LIMIT 1', 'top', 'Longest gap between updates'),
('Same Day Updates', 'SELECT name, COUNT(DISTINCT date) as days FROM updates WHERE date >= {PARAM_2} GROUP BY name HAVING COUNT(*) > COUNT(DISTINCT date) * 2 ORDER BY COUNT(*) DESC LIMIT 1', 'top', 'Multiple updates per day most often'),
('Consecutive Leave', 'SELECT name, COUNT(*) as streak FROM (SELECT name, date, date(date, ''-'' || (ROW_NUMBER() OVER (PARTITION BY name ORDER BY date) - 1) || '' days'') as grp FROM updates WHERE status = ''leave'') GROUP BY name, grp ORDER BY streak DESC LIMIT 1', 'top', 'Longest consecutive leave streak'),
('Consistent Daily', 'SELECT name, COUNT(DISTINCT date) as days FROM updates WHERE date >= date(''now'', ''-14 days'') AND status != ''leave'' GROUP BY name HAVING days >= 10 ORDER BY days DESC LIMIT 1', 'top', 'Updated most days in last 14 days'),
('Update Every Other Day', 'SELECT name, COUNT(DISTINCT date) as cnt FROM updates WHERE date >= {PARAM_2} GROUP BY name HAVING cnt >= 10 ORDER BY cnt DESC LIMIT 1', 'top', 'Most distinct active days'),
('Consistent Updater', 'SELECT name, COUNT(DISTINCT date) as days FROM updates WHERE date >= date(''now'', ''-30 days'') AND status != ''leave'' GROUP BY name ORDER BY days DESC LIMIT 1', 'top', 'Most active days in last 30 days'),
('Sporadic Updater', 'SELECT name, COUNT(DISTINCT date) as days FROM updates WHERE date >= date(''now'', ''-30 days'') AND status != ''leave'' GROUP BY name ORDER BY days ASC LIMIT 1', 'top', 'Fewest active days in last 30 days');

