INSERT OR IGNORE INTO badge_rules (badge_name, sql_query, result_type, description) VALUES
('Most Leave Days', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most total leave days in 90 days'),
('Least Leave Days', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt ASC LIMIT 1', 'top', 'Fewest leave days in 90 days'),
('AL Collector', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND leave_type = ''AL'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most annual leave days'),
('MC Collector', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND leave_type = ''MC'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most medical leave days'),
('EL User', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND leave_type = ''EL'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most emergency leave days'),
('Leave Friday', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND strftime(''%w'', date) = ''5'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most Friday leaves'),
('Leave Monday', 'SELECT name, COUNT(*) as cnt FROM updates WHERE status = ''leave'' AND strftime(''%w'', date) = ''1'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most Monday leaves');

-- ============================================================================
-- SECTION 10: Advanced/complex badges (joins, windows, analytics)
-- ============================================================================

INSERT OR IGNORE INTO badge_rules (badge_name, sql_query, result_type, description) VALUES
('Fastest Done', 'SELECT a.name, julianday(b.date) - julianday(a.date) as days FROM updates a JOIN updates b ON a.name = b.name AND a.module = b.module WHERE a.status = ''in_progress'' AND b.status = ''done'' AND b.date >= a.date AND b.date >= {PARAM_1} ORDER BY days ASC LIMIT 1', 'top', 'Fastest task completion time'),
('Rapid Turnaround', 'SELECT a.name, MIN(julianday(b.date) - julianday(a.date)) as days FROM updates a JOIN updates b ON a.name = b.name AND a.module = b.module WHERE a.status = ''in_progress'' AND b.status = ''done'' AND b.date >= a.date AND b.date >= date(''now'', ''-90 days'') GROUP BY a.name ORDER BY days ASC LIMIT 1', 'top', 'Quickest resolution of in_progress to done'),
('Fresh Start', 'SELECT name, MIN(date) as first_date FROM updates GROUP BY name ORDER BY first_date DESC LIMIT 1', 'top', 'Newest team member'),
('Veteran', 'SELECT name, MIN(date) as first_date FROM updates GROUP BY name ORDER BY first_date ASC LIMIT 1', 'top', 'Longest serving team member'),
('Leave Adjacent', 'SELECT name, COUNT(*) as cnt FROM updates a WHERE a.status != ''leave'' AND EXISTS (SELECT 1 FROM updates b WHERE b.name = a.name AND b.status = ''leave'' AND b.date = date(a.date, ''-1 day'')) AND a.date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most work days right after leave'),
('Post-Leave Comeback', 'SELECT name, COUNT(*) as cnt FROM updates a WHERE a.status = ''done'' AND EXISTS (SELECT 1 FROM updates b WHERE b.name = a.name AND b.status = ''leave'' AND b.date = date(a.date, ''-1 day'')) AND a.date >= {PARAM_1} GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most done tasks after returning from leave'),
('Phoenix Riser', 'SELECT name, COUNT(*) as cnt FROM updates a WHERE a.status = ''done'' AND date >= date(''now'', ''-90 days'') AND EXISTS (SELECT 1 FROM updates b WHERE b.name = a.name AND b.status = ''blocked'' AND b.date < a.date AND julianday(a.date) - julianday(b.date) <= 7) GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Overcame blockers within a week'),
('Steady Eddie', 'SELECT name, COUNT(DISTINCT date) as days, MAX(date) as last, MIN(date) as first FROM updates WHERE status != ''leave'' AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY (days * 100.0 / (julianday(last) - julianday(first) + 1)) DESC LIMIT 1', 'top', 'Most consistent update pace'),
('Multi-Task Day', 'SELECT name, date, COUNT(DISTINCT module) as cnt, COUNT(*) as total FROM updates WHERE status != ''leave'' AND date >= date(''now'', ''-90 days'') GROUP BY name, date HAVING cnt >= 3 ORDER BY total DESC LIMIT 1', 'top', 'Most modules in a single day with at least 3'),
('Big Jumper', 'SELECT name, MAX(gap) as max_gap FROM (SELECT name, date, julianday(date) - julianday(LAG(date) OVER (PARTITION BY name ORDER BY date)) as gap FROM updates WHERE status != ''leave'') WHERE gap IS NOT NULL GROUP BY name ORDER BY max_gap DESC LIMIT 1', 'top', 'Longest gap between non-leave updates'),
('Gap Filler', 'SELECT name, COUNT(*) as cnt FROM (SELECT name, date, julianday(date) - julianday(LAG(date) OVER (PARTITION BY name ORDER BY date)) as gap FROM updates WHERE status != ''leave'') WHERE gap IS NOT NULL AND gap <= 2 AND date >= date(''now'', ''-90 days'') GROUP BY name ORDER BY cnt DESC LIMIT 1', 'top', 'Most back-to-back work days'),
('First In Last Out', 'SELECT name, MIN(strftime(''%H'', created_at)) as first_hour, MAX(strftime(''%H'', created_at)) as last_hour FROM updates WHERE date >= date(''now'', ''-90 days'') GROUP BY name HAVING first_hour <= ''08'' AND last_hour >= ''19'' ORDER BY COUNT(*) DESC LIMIT 1', 'top', 'Updates from before 8 AM to after 7 PM'),
('Update Frequency High', 'SELECT name, CAST(COUNT(*) as REAL) / COUNT(DISTINCT date) as freq FROM updates WHERE date >= date(''now'', ''-30 days'') AND status != ''leave'' GROUP BY name ORDER BY freq DESC LIMIT 1', 'top', 'Highest update frequency in last 30 days'),
('Update Frequency Low', 'SELECT name, CAST(COUNT(*) as REAL) / NULLIF(COUNT(DISTINCT date), 0) as freq FROM updates WHERE date >= date(''now'', ''-30 days'') AND status != ''leave'' GROUP BY name ORDER BY freq ASC LIMIT 1', 'top', 'Lowest update frequency in last 30 days'),
('Longest Gap Overall', 'SELECT name, MAX(julianday(date) - julianday(prev_date)) as gap FROM (SELECT name, date, LAG(date) OVER (PARTITION BY name ORDER BY date) as prev_date FROM updates WHERE status != ''leave'') WHERE prev_date IS NOT NULL ORDER BY gap DESC LIMIT 1', 'top', 'Longest gap between updates overall');